'use client'
import { cn, useSignal, useSignalEffect, useSignals } from '@cascivo/core'
import { builtin, t } from '@cascivo/i18n'
import type { ReactNode } from 'react'
import styles from './app-shell.module.css'
import { createShellState, type ShellState } from './shell-state'

export interface AppShellProps {
  header: ReactNode
  sideNav?: ReactNode
  aside?: ReactNode
  /** Optional sticky footer rendered below the content area. */
  footer?: ReactNode
  children: ReactNode
  persistKey?: string | false
  /** External shell state (from createShellState). Created internally when omitted. */
  state?: ShellState
  className?: string | undefined
  /**
   * push (default): sidebar takes grid space; content shifts when sidebar expands/collapses.
   * overlay: sidebar floats over content; content area never shifts.
   */
  sideNavMode?: 'push' | 'overlay'
}

export function AppShell({
  header,
  sideNav,
  aside,
  footer,
  children,
  persistKey = 'cascade.appshell',
  state,
  className,
  sideNavMode = 'push',
}: AppShellProps) {
  useSignals()

  // Lazy-init shell state (house pattern)
  const store = useSignal<ShellState | null>(null)
  if (store.peek() === null) {
    store.value = state ?? createShellState({ persistKey })
  }
  const shell = store.peek()!

  useSignalEffect(() => {
    if (!shell.sideNavOpen.value) return
    const onKey = (e: globalThis.KeyboardEvent) => {
      if (e.key === 'Escape') shell.sideNavOpen.value = false
    }
    document.addEventListener('keydown', onKey)
    return () => document.removeEventListener('keydown', onKey)
  })

  return (
    <div
      className={cn(styles['shell'], className)}
      data-collapsed={shell.sideNavCollapsed.value || undefined}
      data-drawer={shell.sideNavOpen.value ? 'open' : undefined}
      data-sidenav-mode={sideNavMode}
    >
      {shell.loadingProgress.value !== null && (
        <div
          className={styles['loading-bar']}
          role="progressbar"
          aria-valuemin={0}
          aria-valuemax={100}
          aria-valuenow={Math.round(shell.loadingProgress.value * 100)}
          data-state={shell.loadingError.value !== null ? 'error' : 'active'}
        >
          <div
            className={styles['loading-bar-fill']}
            style={{ ['--_progress' as string]: String(shell.loadingProgress.value) }}
          />
        </div>
      )}
      {shell.loadingError.value !== null && (
        <div role="alert" className={styles['loading-error']}>
          <span>{shell.loadingError.value}</span>
          <button
            type="button"
            className={styles['loading-error-dismiss']}
            aria-label={t(builtin.appShell.dismissError)}
            onClick={() => shell.clearLoadingError()}
          >
            <svg width="12" height="12" viewBox="0 0 12 12" fill="none" aria-hidden="true">
              <path
                d="M3 3l6 6M9 3l-6 6"
                stroke="currentColor"
                strokeWidth="1.5"
                strokeLinecap="round"
              />
            </svg>
          </button>
        </div>
      )}
      <div className={styles['header']}>{header}</div>
      {sideNav && (
        <div
          className={styles['nav']}
          data-state={shell.sideNavCollapsed.value ? 'collapsed' : 'expanded'}
        >
          <div className={styles['nav-content']}>{sideNav}</div>
        </div>
      )}
      {sideNav && (
        <div
          data-testid="cascade-shell-scrim"
          aria-hidden="true"
          className={styles['scrim']}
          onClick={() => {
            shell.sideNavOpen.value = false
          }}
        />
      )}
      <main id="cascade-main" tabIndex={-1} className={styles['main']}>
        {children}
      </main>
      {aside && (
        <div className={styles['aside']} data-state={shell.asideOpen.value ? 'open' : 'closed'}>
          {aside}
        </div>
      )}
      {footer && <div className={styles['footer']}>{footer}</div>}
    </div>
  )
}

import { signal, type Signal } from '@cascivo/core'
import { persistedSignal } from '@cascivo/storage'
import { minWidth } from '@cascivo/tokens/screens'

export interface ShellState {
  /** Desktop: side nav collapsed to the icon rail. Persisted. */
  sideNavCollapsed: Signal<boolean>
  /** Mobile: side nav drawer open. Never persisted. */
  sideNavOpen: Signal<boolean>
  /** Right aside visible. Persisted. */
  asideOpen: Signal<boolean>
  /** Hamburger handler: drawer on mobile, collapse on desktop (resolved at call time). */
  toggleSideNav: () => void
  toggleAside: () => void
  /** Top loading bar: null = hidden, 0–1 = determinate progress. Never persisted. */
  loadingProgress: Signal<number | null>
  /** Loading error message; non-null renders the dismissible alert strip. */
  loadingError: Signal<string | null>
  /** Show the bar at 0. Clears any error and any pending hide timer. */
  startLoading: () => void
  /** Update progress; clamped to [0, 1]. No-op if the bar is hidden. */
  setLoadingProgress: (fraction: number) => void
  /** Snap to 1 and hide after a short fade (400ms). */
  finishLoading: () => void
  /** Keep the bar (destructive style) and show a dismissible message. */
  failLoading: (message?: string) => void
  /** Dismiss the error and hide the bar. */
  clearLoadingError: () => void
}

export interface CreateShellStateOptions {
  /** Storage key prefix; false disables persistence. Default: 'cascade.shell'. */
  persistKey?: string | false
}

const DESKTOP = minWidth('lg') // '(min-width: 64rem)' — canonical lg breakpoint

function isDesktop(): boolean {
  if (typeof window === 'undefined' || typeof window.matchMedia !== 'function') return true
  return window.matchMedia(DESKTOP).matches
}

export function createShellState(options: CreateShellStateOptions = {}): ShellState {
  const key = options.persistKey ?? 'cascade.shell'
  const sideNavCollapsed = key === false ? signal(false) : persistedSignal(`${key}.sidenav`, false)
  const asideOpen = key === false ? signal(true) : persistedSignal(`${key}.aside`, true)
  const sideNavOpen = signal(false)

  const loadingProgress = signal<number | null>(null)
  const loadingError = signal<string | null>(null)
  let hideTimer: ReturnType<typeof setTimeout> | undefined

  return {
    sideNavCollapsed,
    sideNavOpen,
    asideOpen,
    toggleSideNav: () => {
      if (isDesktop()) {
        sideNavCollapsed.value = !sideNavCollapsed.value
      } else {
        sideNavOpen.value = !sideNavOpen.value
      }
    },
    toggleAside: () => {
      asideOpen.value = !asideOpen.value
    },
    loadingProgress,
    loadingError,
    startLoading: () => {
      if (hideTimer !== undefined) clearTimeout(hideTimer)
      loadingError.value = null
      loadingProgress.value = 0
    },
    setLoadingProgress: (fraction) => {
      if (loadingProgress.value === null) return
      loadingProgress.value = Math.min(1, Math.max(0, fraction))
    },
    finishLoading: () => {
      loadingProgress.value = 1
      if (hideTimer !== undefined) clearTimeout(hideTimer)
      hideTimer = setTimeout(() => {
        loadingProgress.value = null
      }, 400)
    },
    failLoading: (message) => {
      loadingError.value = message ?? 'Loading failed'
    },
    clearLoadingError: () => {
      loadingError.value = null
      loadingProgress.value = null
    },
  }
}

@layer cascivo.component {
  .shell {
    display: grid;
    grid-template:
      'header header header' auto
      'nav    main    aside ' 1fr
      'footer footer  footer' auto
      / auto minmax(0, 1fr) auto;
    block-size: 100dvh;
    overflow: hidden;
    position: relative;
  }

  .header {
    grid-area: header;
    /* Naturally stays at top — grid row is auto, shell is overflow:hidden */
    z-index: var(--cascivo-z-raised, 10);
  }

  .footer {
    grid-area: footer;
    /* Naturally stays at bottom — grid row is auto after the 1fr content row */
    z-index: var(--cascivo-z-raised, 10);
  }

  .nav {
    grid-area: nav;
    position: relative;
    display: flex;
    flex-direction: column;
    /* Cap to the grid track so a tall nav scrolls inside .nav-content instead of
       growing past the row (overflow:visible would set the auto-min to the
       content height and hide the bottom entries). */
    min-block-size: 0;
  }

  .nav-content {
    flex: 1;
    min-block-size: 0;
    overflow-y: auto;
    overflow-x: hidden;
  }

  .main {
    grid-area: main;
    min-inline-size: 0;
    overflow-y: auto;
  }

  .aside {
    grid-area: aside;
    overflow-y: auto;
    overflow-x: hidden;
    inline-size: var(--cascivo-shell-aside-inline-size, 18rem);
    transition: inline-size var(--cascivo-duration-200, 200ms) var(--cascivo-ease-out, ease);
  }

  .aside[data-state='closed'] {
    inline-size: 0;
    visibility: hidden;
  }

  .scrim {
    display: none;
  }

  /* Canonical lg breakpoint (64rem = SCREEN.lg). Below this: mobile drawer mode. */
  @media (max-width: 64rem) {
    .shell {
      grid-template:
        'header' auto
        'main' 1fr
        'footer' auto / minmax(0, 1fr);
    }

    .aside {
      /* On mobile, aside slides in as an overlay — stays in a11y tree, keyboard-reachable when toggled */
      position: fixed;
      inset-block: 0;
      inset-inline-end: 0;
      z-index: var(--cascivo-z-overlay, 200);
      background: var(--cascivo-color-surface);
      inline-size: var(--cascivo-shell-aside-inline-size, 18rem);
      translate: 100% 0;
      transition: translate var(--cascivo-motion-exit, 200ms ease);
      box-shadow: var(--cascivo-shadow-overlay);
      overflow-y: auto;
      overflow-x: hidden;
    }

    :dir(rtl) .aside {
      inset-inline-end: auto;
      inset-inline-start: 0;
      translate: -100% 0;
    }

    .aside[data-state='open'] {
      translate: 0 0;
      transition: translate var(--cascivo-motion-enter, 200ms ease);
    }

    :dir(rtl) .aside[data-state='open'] {
      translate: 0 0;
    }

    .toggle {
      display: none;
    }

    .nav {
      position: fixed;
      inset-block: 0;
      inset-inline-start: 0;
      z-index: 40;
      inline-size: var(--cascivo-sidenav-inline-size, 16rem);
      background: var(--cascivo-color-surface);
      translate: -100% 0;
      transition: translate var(--cascivo-motion-exit, 200ms ease);
      overscroll-behavior: contain;
    }

    :dir(rtl) .nav {
      translate: 100% 0;
    }

    .shell[data-drawer='open'] .nav {
      translate: 0 0;
      transition: translate var(--cascivo-motion-enter, 200ms ease);
    }

    .shell[data-drawer='open'] .scrim {
      display: block;
      position: fixed;
      inset: 0;
      z-index: 30;
      background: var(--cascivo-color-scrim, oklch(0 0 0 / 40%));
    }
  }

  @media (prefers-reduced-motion: reduce) {
    .nav {
      transition: none;
    }
  }

  /* Overlay mode: nav floats over content; main always spans the full width */
  .shell[data-sidenav-mode='overlay'] .main {
    grid-column: nav-start / main-end;
  }

  .shell[data-sidenav-mode='overlay'] .nav {
    z-index: 5;
    box-shadow: var(--cascivo-shadow-md);
  }

  .loading-bar {
    position: absolute;
    inset-block-start: 0;
    inset-inline: 0;
    block-size: 3px;
    z-index: calc(var(--cascivo-z-raised, 10) + 1);
    background: transparent;
    pointer-events: none;
  }

  .loading-bar-fill {
    block-size: 100%;
    inline-size: calc(var(--_progress, 0) * 100%);
    background: var(--cascivo-color-accent);
    transition: inline-size var(--cascivo-duration-200, 200ms) var(--cascivo-ease-out, ease);
  }

  .loading-bar[data-state='error'] .loading-bar-fill {
    background: var(--cascivo-color-destructive);
  }

  .loading-error {
    grid-area: main;
    align-self: start;
    justify-self: stretch;
    z-index: var(--cascivo-z-raised, 10);
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: var(--cascivo-space-3);
    padding: var(--cascivo-space-2) var(--cascivo-space-4);
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-destructive);
    background: var(--cascivo-color-destructive-subtle);
    border-block-end: 1px solid var(--cascivo-color-destructive);
  }

  .loading-error-dismiss {
    display: inline-flex;
    padding: var(--cascivo-space-1);
    border: none;
    background: none;
    color: inherit;
    cursor: pointer;
    border-radius: var(--cascivo-radius-component);
  }

  .loading-error-dismiss:focus-visible {
    outline: none;
    box-shadow: var(--cascivo-focus-ring);
  }
}
